public class CacPhepToan {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 4;
		int b = 2;
		System.out.println("<--- Các Phép Toán --->");

		System.out.printf("Phép cộng: %d + %d = %d\n", a, b, a + b);
		System.out.printf("Phép trừ : %d - %d = %d\n", a, b, a - b);
		System.out.printf("Phép nhân: %d * %d = %d\n", a, b, a * b);
		System.out.printf("Phép chia: %d / %d = %d\n", a, b, a / b);
	}

}
